class Solution(object):
    def minMoves(self, balance):
        n = len(balance)
        total = sum(balance)
        if total < 0:
            return -1

        # Find the negative index (at most one)
        neg_idx = -1
        for i, v in enumerate(balance):
            if v < 0:
                neg_idx = i
                break

        if neg_idx == -1:
            return 0  # already balanced

        deficit = -balance[neg_idx]
        # Sort positive values by their circular distance to neg_idx
        positives = []
        for i, v in enumerate(balance):
            if v > 0:
                # Circular distance: min(|i - neg_idx|, n - |i - neg_idx|)
                d = abs(i - neg_idx)
                dist = min(d, n - d)
                positives.append((dist, v))

        positives.sort()
        moves = 0
        for dist, v in positives:
            if deficit <= 0:
                break
            take = min(v, deficit)
            moves += take * dist
            deficit -= take

        return moves if deficit <= 0 else -1
